/**
 * Compute the
 * <a href="http://mathworld.wolfram.com/InverseTangent.html" TARGET="_top">
 * inverse tangent</a> of this complex number.
 * Implements the formula:
 * <pre>
 *  <code>
 *   atan(z) = (i/2) log((i + z)/(i - z))
 *  </code>
 * </pre>
 * Returns {@link Complex#NaN} if either real or imaginary part of the
 * input argument is {@code NaN} or infinite.
 *
 * @return the inverse tangent of this complex number
 * @since 1.2
 */
public Complex atan() {
    if (isNaN) {
        return NaN;
    }

    // Special handling for z = i (where i + z = 2i and i - z = 0)
    // This would cause division by zero, but mathematically atan(i) should be infinite
    if (this.equals(I)) {
        return createComplex(0.0, Double.POSITIVE_INFINITY);
    }

    // Special handling for z = -i (where i + z = 0 and i - z = 2i)
    // This would cause division by zero, but mathematically atan(-i) should be infinite
    if (this.equals(I.negate())) {
        return createComplex(0.0, Double.NEGATIVE_INFINITY);
    }

    return this.add(I).divide(I.subtract(this)).log()
        .multiply(I.divide(createComplex(2.0, 0.0)));
}

